const config = $('Workflow Config').first().json;
const rows = $input.first().json;
const store = Array.isArray(rows) ? rows[0] : rows;

if (!store?.id) {
  throw new Error(`No Lazada store row found for seller ${config.lazadaSellerId}. Insert or update it in Supabase first.`);
}

if (!store.is_active) {
  throw new Error(`Lazada store ${store.name || store.shop_id} is disabled in Supabase.`);
}

if (!store.refresh_token) {
  throw new Error(`Lazada store ${store.name || store.shop_id} is missing refresh_token.`);
}

return [{
  json: {
    ...config,
    storeId: store.id,
    storeName: store.name,
    shopId: store.shop_id,
    accessToken: store.access_token || '',
    refreshToken: store.refresh_token,
    tokenExpiry: store.token_expiry || null
  }
}];

function rightRotate(value, amount) {
  return (value >>> amount) | (value << (32 - amount));
}

function sha256(ascii) {
  const mathPow = Math.pow;
  const maxWord = mathPow(2, 32);
  let result = '';
  const words = [];
  const asciiBitLength = ascii.length * 8;
  let hash = [];
  let k = [];
  let primeCounter = 0;
  const isComposite = {};

  for (let candidate = 2; primeCounter < 64; candidate++) {
    if (!isComposite[candidate]) {
      for (let i = 0; i < 313; i += candidate) {
        isComposite[i] = candidate;
      }
      hash[primeCounter] = (mathPow(candidate, 0.5) * maxWord) | 0;
      k[primeCounter++] = (mathPow(candidate, 1 / 3) * maxWord) | 0;
    }
  }

  ascii += '\x80';
  while ((ascii.length % 64) - 56) ascii += '\x00';
  for (let i = 0; i < ascii.length; i++) {
    const j = ascii.charCodeAt(i);
    words[i >> 2] |= j << (((3 - i) % 4) * 8);
  }
  words[words.length] = (asciiBitLength / maxWord) | 0;
  words[words.length] = asciiBitLength;

  for (let j = 0; j < words.length;) {
    const w = words.slice(j, (j += 16));
    const oldHash = hash.slice(0);

    for (let i = 0; i < 64; i++) {
      const w15 = w[i - 15];
      const w2 = w[i - 2];
      const a = hash[0];
      const e = hash[4];
      const temp1 = hash[7] + (rightRotate(e, 6) ^ rightRotate(e, 11) ^ rightRotate(e, 25)) + ((e & hash[5]) ^ (~e & hash[6])) + k[i] + (w[i] = i < 16 ? w[i] : (w[i - 16] + (rightRotate(w15, 7) ^ rightRotate(w15, 18) ^ (w15 >>> 3)) + w[i - 7] + (rightRotate(w2, 17) ^ rightRotate(w2, 19) ^ (w2 >>> 10))) | 0);
      const temp2 = (rightRotate(a, 2) ^ rightRotate(a, 13) ^ rightRotate(a, 22)) + ((a & hash[1]) ^ (a & hash[2]) ^ (hash[1] & hash[2]));
      hash = [(temp1 + temp2) | 0].concat(hash);
      hash[4] = (hash[4] + temp1) | 0;
      hash.pop();
    }

    for (let i = 0; i < 8; i++) {
      hash[i] = (hash[i] + oldHash[i]) | 0;
    }
  }

  for (let i = 0; i < 8; i++) {
    for (let j = 3; j + 1; j--) {
      const b = (hash[i] >> (j * 8)) & 255;
      result += ((b < 16 ? '0' : '') + b.toString(16));
    }
  }

  return result;
}

function hexToBinary(hex) {
  let output = '';
  for (let i = 0; i < hex.length; i += 2) {
    output += String.fromCharCode(parseInt(hex.slice(i, i + 2), 16));
  }
  return output;
}

function hmacSha256(key, message) {
  const blockSize = 64;
  let normalizedKey = key;

  if (normalizedKey.length > blockSize) {
    normalizedKey = hexToBinary(sha256(normalizedKey));
  }

  if (normalizedKey.length < blockSize) {
    normalizedKey = normalizedKey.padEnd(blockSize, '\x00');
  }

  let oKeyPad = '';
  let iKeyPad = '';

  for (let i = 0; i < blockSize; i++) {
    const code = normalizedKey.charCodeAt(i);
    oKeyPad += String.fromCharCode(code ^ 0x5c);
    iKeyPad += String.fromCharCode(code ^ 0x36);
  }

  return sha256(oKeyPad + hexToBinary(sha256(iKeyPad + message))).toUpperCase();
}

const config = $input.first().json;
const pagePath = '/auth/token/refresh';
const timestamp = Date.now().toString();
const params = {
  app_key: config.appKey,
  refresh_token: config.refreshToken,
  sign_method: 'sha256',
  timestamp
};
const sortedKeys = Object.keys(params).sort();
const concatenated = sortedKeys.map((key) => key + params[key]).join('');
const sign = hmacSha256(config.appSecret, pagePath + concatenated);
const query = sortedKeys.map((key) => `${encodeURIComponent(key)}=${encodeURIComponent(params[key])}`).join('&');
const requestUrl = `${config.lazadaAuthBase}/rest${pagePath}?${query}&sign=${sign}`;

return [{
  json: {
    ...config,
    refreshRequestUrl: requestUrl
  }
}];

