function toRecord(value) {
  return value && typeof value === 'object' && !Array.isArray(value) ? value : {};
}

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function asString(value) {
  return typeof value === 'string' && value.trim().length > 0 ? value.trim() : undefined;
}

function lower(value) {
  return typeof value === 'string' ? value.toLowerCase() : '';
}

function normalizePlatformStatus(value) {
  if (typeof value !== 'string' || value.trim().length === 0) {
    return 'unknown';
  }

  return value
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '') || 'unknown';
}

function extractOrders(response) {
  const data = response.data || response.result?.data || response.result || response;
  if (Array.isArray(data?.orders)) return data.orders;
  if (Array.isArray(data?.order_list)) return data.order_list;
  if (Array.isArray(data)) return data;
  return [];
}

function extractItemsFromOrder(order) {
  return asArray(
    order.order_items ||
      order.orderItems ||
      order.items ||
      order.item_list ||
      order.order_item_list ||
      order.orderItemList
  ).map((item) => toRecord(item));
}

function uniqueStrings(values) {
  return Array.from(new Set(values.filter((value) => typeof value === 'string' && value.length > 0)));
}

function pickBuyerName(order) {
  const shipping = order.address_shipping || order.shipping_address || {};
  const fromOrder = [order.customer_first_name, order.customer_last_name].filter(Boolean).join(' ').trim();
  const fromShipping = [shipping.first_name, shipping.last_name].filter(Boolean).join(' ').trim();
  return fromOrder || fromShipping || order.customer_name || order.buyer_name || null;
}

function collectStatuses(order) {
  return uniqueStrings([
    ...asArray(order.statuses).map((value) => lower(value)),
    ...asArray(order.order_statuses).map((value) => lower(value)),
    lower(order.status),
    lower(order.order_status),
    lower(order.orderStatus),
    lower(order.shipping_status),
    lower(order.shippingStatus),
    lower(order.fulfillment_status),
    lower(order.fulfillmentStatus)
  ]);
}

function isEligibleOrder(order) {
  const platformOrderId = String(order.order_id || order.orderId || '').trim();
  return platformOrderId.length > 0;
}

function mapItem(item) {
  return {
    order_item_id: item.order_item_id ?? item.orderItemId ?? null,
    item_name: item.name ?? item.item_name ?? item.product_name ?? null,
    sku: item.sku ?? item.shop_sku ?? item.seller_sku ?? item.model_sku ?? null,
    quantity: item.quantity ?? item.qty ?? item.model_quantity_purchased ?? null,
    status: item.status ?? item.order_item_status ?? null,
    package_id: item.package_id ?? item.packageId ?? null,
    tracking_code: item.tracking_code ?? item.trackingCode ?? item.tracking_no ?? item.tracking_number ?? null,
    shipping_type: item.shipping_type ?? item.shippingType ?? null,
    delivery_option_sof: item.delivery_option_sof ?? null
  };
}

function pickBarcodeValue(order, items) {
  const trackingValues = uniqueStrings(
    items
      .map((item) => asString(item.tracking_code) || asString(item.trackingCode) || asString(item.tracking_no) || asString(item.tracking_number))
      .filter(Boolean)
  );

  if (trackingValues.length > 0) {
    return trackingValues[0];
  }

  const packageValues = uniqueStrings(
    items
      .map((item) => asString(item.package_id) || asString(item.packageId))
      .filter(Boolean)
  );

  if (packageValues.length > 0) {
    return packageValues[0];
  }

  return String(order.order_id || order.orderId || '').trim() || null;
}

const config = $('Normalize Lazada Token Set').first().json;
const pageResponses = $input.all().map((item) => item.json);
const orders = [];

for (const response of pageResponses) {
  orders.push(...extractOrders(response));
}

const deduped = [];
const seen = new Set();
for (const order of orders) {
  const platformOrderId = String(order.order_id || order.orderId || '').trim();
  if (!platformOrderId || seen.has(platformOrderId)) {
    continue;
  }
  seen.add(platformOrderId);
  deduped.push(order);
}

const eligibleOrders = deduped.filter(isEligibleOrder);

return eligibleOrders.map((order) => {
  const platformOrderId = String(order.order_id || order.orderId || '').trim();
  const embeddedItems = extractItemsFromOrder(order).map(mapItem);
  const statuses = collectStatuses(order);
  const params = {
    access_token: config.accessToken,
    app_key: config.appKey,
    order_id: platformOrderId,
    sign_method: 'sha256',
    timestamp: String(Date.now())
  };

  return {
    json: {
      store_id: config.storeId,
      platform_order_id: platformOrderId,
      barcode_value: pickBarcodeValue(order, embeddedItems),
      buyer_name: pickBuyerName(order),
      platform_status: normalizePlatformStatus(statuses[0]),
      embeddedItems,
      embeddedItemCount: embeddedItems.length,
      itemSyncSource: embeddedItems.length > 0 ? 'orders_get' : 'none',
      itemsRequestUrl: buildSignedUrl(config, '/order/items/get', params),
      supabaseUrl: config.supabaseUrl,
      serviceRoleKey: config.serviceRoleKey
    }
  };
});

const inputItems = $input.all().map((item) => item.json);

if (inputItems.length === 0) {
  return [];
}

const config = $('Normalize Lazada Token Set').first().json;
const template = inputItems[0];
const batchSize = Math.max(
  1,
  Math.min(500, Number(template.supabaseBatchSize || config.supabaseBatchSize || '50') || 50)
);

const records = inputItems.map((item) => {
  if (typeof item.requestBody === 'string') {
    return JSON.parse(item.requestBody);
  }

  const record = {
    store_id: item.store_id,
    platform_order_id: item.platform_order_id,
    barcode_value: item.barcode_value,
    buyer_name: item.buyer_name,
    platform_status: item.platform_status
  };

  if ('items_json' in item) {
    record.items_json = item.items_json;
  }

  return record;
});

function getShapeKey(record) {
  return Object.keys(record).sort().join('|');
}

const groupedRecords = new Map();
for (const record of records) {
  const shapeKey = getShapeKey(record);
  if (!groupedRecords.has(shapeKey)) {
    groupedRecords.set(shapeKey, []);
  }
  groupedRecords.get(shapeKey).push(record);
}

const batches = [];
for (const [shapeKey, group] of groupedRecords.entries()) {
  for (let index = 0; index < group.length; index += batchSize) {
    batches.push({
      shapeKey,
      records: group.slice(index, index + batchSize)
    });
  }
}

return batches.map((batch, index) => ({
  json: {
    ...template,
    requestBody: JSON.stringify(batch.records),
    batchIndex: index + 1,
    batchCount: batches.length,
    recordCount: batch.records.length,
    recordShape: batch.shapeKey,
    supabaseBatchSize: batchSize
  }
}));

function toRecord(value) {
  return value && typeof value === 'object' && !Array.isArray(value) ? value : {};
}

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function uniqueStrings(values) {
  return Array.from(new Set(values.filter((value) => typeof value === 'string' && value.length > 0)));
}

function asString(value) {
  return typeof value === 'string' && value.trim().length > 0 ? value.trim() : undefined;
}

function normalizeLazadaOrderItems(response) {
  const data = response?.body?.data || response?.body?.result?.data || response?.body?.result || response?.body || response?.data || response?.result?.data || response?.result || response;
  if (Array.isArray(data)) return data.map((item) => toRecord(item));

  const record = toRecord(data);
  const list = asArray(record.order_items || record.orderItems || record.items || record.list);
  return list.map((item) => toRecord(item));
}

function mapItem(item) {
  return {
    order_item_id: item.order_item_id ?? item.orderItemId ?? null,
    item_name: item.name ?? item.item_name ?? item.product_name ?? null,
    sku: item.sku ?? item.shop_sku ?? item.seller_sku ?? item.model_sku ?? null,
    quantity: item.quantity ?? item.qty ?? item.model_quantity_purchased ?? null,
    status: item.status ?? item.order_item_status ?? null,
    package_id: item.package_id ?? item.packageId ?? null,
    tracking_code: item.tracking_code ?? item.trackingCode ?? item.tracking_no ?? item.tracking_number ?? null,
    shipping_type: item.shipping_type ?? item.shippingType ?? null,
    delivery_option_sof: item.delivery_option_sof ?? null
  };
}

function pickBarcodeValue(order, items) {
  const trackingValues = uniqueStrings(
    items
      .map((item) => asString(item.tracking_code) || asString(item.trackingCode) || asString(item.tracking_no) || asString(item.tracking_number))
      .filter(Boolean)
  );

  if (trackingValues.length > 0) {
    return trackingValues[0];
  }

  const packageValues = uniqueStrings(
    items
      .map((item) => asString(item.package_id) || asString(item.packageId))
      .filter(Boolean)
  );

  if (packageValues.length > 0) {
    return packageValues[0];
  }

  return order.barcode_value || order.platform_order_id || null;
}

function extractErrorMessage(item) {
  const statusCode = item?.json?.statusCode;
  const body = item?.json?.body;
  const explicitMessage =
    item?.error?.message ||
    item?.json?.error?.message ||
    item?.json?.error?.description ||
    item?.json?.error ||
    body?.message ||
    body?.error?.message ||
    body?.error?.description ||
    body?.error ||
    item?.json?.message ||
    item?.json?.description ||
    null;

  if (typeof explicitMessage === 'string' && explicitMessage.trim().length > 0) {
    return explicitMessage.trim();
  }

  if (typeof statusCode === 'number' && statusCode >= 400) {
    return 'HTTP ' + statusCode;
  }

  return null;
}

const responseItems = $input.all();
const preparedItems = $('Map Lazada Orders For Supabase').all();

return preparedItems.map((preparedItem, index) => {
  const prepared = preparedItem.json;
  const responseItem = responseItems[index] || {};
  const responseJson = responseItem.json || {};
  const fetchedItemsRaw = normalizeLazadaOrderItems(responseJson);
  const fetchedItems = fetchedItemsRaw.map(mapItem);
  const responseError = extractErrorMessage(responseItem);
  const statusCode = responseJson?.statusCode;
  let items = Array.isArray(prepared.embeddedItems) ? prepared.embeddedItems : [];
  let itemSyncSource = prepared.itemSyncSource || 'none';
  let itemsFetchStatus = 'skipped';
  let itemsFetchError = null;

  if (responseError) {
    itemsFetchStatus = 'error';
    itemsFetchError = responseError;
  } else if (fetchedItems.length > 0) {
    items = fetchedItems;
    itemSyncSource = 'items_get';
    itemsFetchStatus = 'success';
  } else if (typeof statusCode === 'number' && statusCode >= 200 && statusCode < 300) {
    itemsFetchStatus = 'empty';
  } else {
    itemsFetchStatus = 'skipped';
  }

  const body = {
    store_id: prepared.store_id,
    platform_order_id: prepared.platform_order_id,
    barcode_value: pickBarcodeValue(prepared, items),
    buyer_name: prepared.buyer_name,
    platform_status: prepared.platform_status || 'unknown'
  };

  if (items.length > 0) {
    body.items_json = items;
  }

  return {
    json: {
      ...body,
      supabaseUrl: prepared.supabaseUrl,
      serviceRoleKey: prepared.serviceRoleKey,
      requestUrl: prepared.supabaseUrl + '/rest/v1/orders?on_conflict=store_id,platform_order_id',
      requestBody: JSON.stringify(body),
      itemSyncSource,
      embeddedItemCount: prepared.embeddedItemCount || 0,
      finalItemCount: items.length,
      itemsFetchStatus,
      itemsFetchError
    }
  };
});
